1	type Cell = [number, number];
2	
3	const cellKey = ([row, col]: Cell): string => `${row},${col}`;
4	
5	const parseKey = (key: string): Cell => {
6	  const [r, c] = key.split(",").map(Number);
7	  return [r, c];
8	};
9	
10	const neighborsOf = ([row, col]: Cell): Cell[] => {
11	  const result: Cell[] = [];
12	  for (let dr = -1; dr <= 1; dr++) {
13	    for (let dc = -1; dc <= 1; dc++) {
14	      if (dr === 0 && dc === 0) continue;
15	      result.push([row + dr, col + dc]);
16	    }
17	  }
18	  return result;
19	};
20	
21	const isNeighbor = ([row, col]: Cell, [otherRow, otherCol]: Cell): boolean =>
22	  !(otherRow === row && otherCol === col) &&
23	  Math.abs(otherRow - row) <= 1 &&
24	  Math.abs(otherCol - col) <= 1;
25	
26	const countNeighbors = (cell: Cell, liveCells: Cell[]): number =>
27	  liveCells.filter((other) => isNeighbor(cell, other)).length;
28	
29	const deadNeighbors = (liveCells: Cell[]): Cell[] => {
30	  const liveSet = new Set(liveCells.map(cellKey));
31	  const candidates = new Set<string>();
32	  for (const cell of liveCells) {
33	    for (const neighbor of neighborsOf(cell)) {
34	      const key = cellKey(neighbor);
35	      if (!liveSet.has(key)) candidates.add(key);
36	    }
37	  }
38	  return [...candidates].map(parseKey);
39	};
40	
41	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
42	  const survivors = liveCells.filter((cell) => {
43	    const neighbors = countNeighbors(cell, liveCells);
44	    return neighbors === 2 || neighbors === 3;
45	  });
46	  const births = deadNeighbors(liveCells).filter(
47	    (cell) => countNeighbors(cell, liveCells) === 3
48	  );
49	  return [...survivors, ...births];
50	};
